function sliderHeader() {
    var swiper = new Swiper('.header-bottom .mySwiper', {
        slidesPerView: "auto",
        spaceBetween: 40,
        speed: 500,
        navigation: {
            nextEl: ".header-bottom .swiper-button-next",
            prevEl: ".header-bottom .swiper-button-prev",
        },
    })

}

function sliderArticles() {
    var swiper = new Swiper('.articles .mySwiper', {
        slidesPerView: 4,
        spaceBetween: 48,
        speed: 500,
        pagination: {
            el: ".articles .swiper-pagination",
            type: "progressbar",
        },
        breakpoints: {
            320: {
                slidesPerView: 1.2,
                spaceBetween: 20,
            },
            577: {
                slidesPerView: 2,
                spaceBetween: 20,
            },
            769: {
                slidesPerView: 3,
                spaceBetween: 20,
            },
            1201: {
                slidesPerView: 4,
                spaceBetween: 48,
            }
        }
    })

}

let SlidersArray = []
function sliderCertificatesCard() {
    $(".certificates-info__slider").each(function(index, el) {
        $(el).attr("data-slider-id", `${index}`)
        SlidersArray[index] = new Swiper(`.certificates-info__slider[data-slider-id="${index}"] .swiper`, {
            slidesPerView: 1,
            spaceBetween: 15,
            speed: 500,
            navigation: {
                nextEl: `.certificates-info__slider[data-slider-id="${index}"] .swiper-button-next`,
                prevEl: `.certificates-info__slider[data-slider-id="${index}"] .swiper-button-prev`,
            },
            pagination: {
                el: `.certificates-info__slider[data-slider-id="${index}"] .swiper-pagination`,
                clickable: true
            },
        })
    })
}

let SlidersArray2 = []
function sliderDocuments() {
    $(".documents__slider").each(function(index, el) {
        $(el).attr("data-slider-id", `${index}`)
        SlidersArray2[index] = new Swiper(`.documents__slider[data-slider-id="${index}"] .swiper`, {
            slidesPerView: 4,
            spaceBetween: 40,
            speed: 500,
            freeMode: true,
            freeModeMomentum: true,
            breakpoints: {
                320: {
                    slidesPerView: 1.5,
                    spaceBetween: 20,
                },
                577: {
                    slidesPerView: 4,
                    spaceBetween: 20,
                },
                993: {
                    slidesPerView: 4,
                    spaceBetween: 48,
                }
            }
        })
    })
}

function sliderSelection() {
    var swiper = new Swiper('.selection .mySwiper', {
        slidesPerView: 1,
        spaceBetween: 15,
        speed: 300,
        allowTouchMove: false,
        navigation: {
            nextEl: ".selection .swiper-button-next",
            prevEl: ".selection .swiper-button-prev",
        },
        on: {
            slideChange: function () {
                const swiperEl = document.querySelector('.selection .mySwiper');

                swiperEl.scrollIntoView({
                    behavior: 'smooth',
                    block: 'start'
                });
            }
        }
    });
}

$(document).ready(function () {
    sliderHeader();
    sliderCertificatesCard();
    sliderArticles();
    sliderDocuments();
    sliderSelection();

    // Burger
    $('.burger').click(function () {
        $(this).toggleClass('burger--active')
        $('body').toggleClass('fixed-body')
    })

    // Search
    $('.search-btn__mob').click(function () {
        $('.search').toggleClass('search--active')
    })

    // Tabs
    $(".tab").click(function () {
        let path = $(this).attr("data-tab-path")
        $(this).siblings(".tab").removeClass("tab--active")
        $(this).addClass("tab--active")

        $(this).parents(".tabs-inner").find(".tab__content").removeClass("tab__content--active")
        $(this).parents(".tabs-inner").find(`.tab__content[data-content-path="${path}"]`).addClass("tab__content--active")
    })

    // Select
    $(".custom_select select").niceSelect()

    // Calc
    $(document).on('click', '.calc .calc-minus', function () {
        let $input = $(this).closest('.calc').find('input');
        let a = +$input.val();

        if (a > 1) {
            $input.val(a - 1);
        }
    });
    $(document).on('click', '.calc .calc-plus', function () {
        let $input = $(this).closest('.calc').find('input');
        let a = +$input.val();

        $input.val(a + 1);
    });

    // Range
    // $(document).on('input', '.range-input', function () {
    //     let value = $(this).val();
    //     let formatted = Number(value).toLocaleString('ru-RU');
    //
    //     $(this)
    //         .closest('.certificates-info__range')
    //         .find('.range-text')
    //         .text(formatted + ' ₽');
    // });

    // Range
    function formatNumber(val) {
        return Number(val).toLocaleString('ru-RU');
    }

    $(document).on('input', '.range-input', function () {
        let $block = $(this).closest('.certificates-info__range');
        let value = +$(this).val();

        if (!$block.find('.range-text').is(':focus')) {
            $block.find('.range-text').text(formatNumber(value));
        }
    });

    $(document).on('input', '.range-text', function () {
        let $el = $(this);
        let $block = $el.closest('.certificates-info__range');
        let $range = $block.find('.range-input');

        let min = +$range.attr('min');
        let max = +$range.attr('max');

        let text = $el.text();
        let cleaned = text.replace(/\D/g, '');

        if (text !== cleaned) {
            $el.text(cleaned);

            let el = this;
            let range = document.createRange();
            let sel = window.getSelection();
            range.selectNodeContents(el);
            range.collapse(false);
            sel.removeAllRanges();
            sel.addRange(range);
        }

        let value = +cleaned;
        if (!value) return;

        if (value < min) value = min;
        if (value > max) value = max;

        $range.val(value);
    });

    $(document).on('blur', '.range-text', function () {
        let $el = $(this);
        let $range = $el.closest('.certificates-info__range').find('.range-input');

        let min = +$range.attr('min');
        let max = +$range.attr('max');

        let value = $el.text().replace(/\D/g, '');
        value = +value;

        if (!value) value = min;

        if (value < min) value = min;
        if (value > max) value = max;

        $range.val(value);

        $el.text(formatNumber(value));
    });

    $(document).on('paste', '.range-text', function (e) {
        e.preventDefault();

        let text = (e.originalEvent || e).clipboardData.getData('text');
        text = text.replace(/\D/g, '');

        document.execCommand('insertText', false, text);
    });

    $(document).on('keydown', '.range-text', function (e) {
        if (e.key === 'Enter') {
            e.preventDefault();
            $(this).blur();
        }
    });

    // Btn
    $('.certificates-info__btn2').click(function () {
        $(this).addClass('active')
    })

    // Clone
    $(document).on('click', '.certificates-info__btn', function (e) {
        e.preventDefault();
        var $parent = $(this).closest('.certificates-info__subgroup');
        var $clone = $parent.clone();
        $clone.addClass('clone');
        $parent.before($clone);
    });

    // Delete
    $(document).on('click', '.delete', function () {
        $(this).closest('.clone').remove();
    });

    // Phone
    const input = document.querySelector("#phone");

    window.intlTelInput(input, {
        initialCountry: "ru",
        separateDialCode: true,
        preferredCountries: ["ru"]
    });

    $('.iti__flag-container').click(function () {
        $(this).toggleClass('active')
    })

    // Modal
    $("[data-modal]").click(function () {
        let modalId = $(this).attr("data-modal")

        openModal(modalId)
    })

    function openModal(modalId){
        $(`#${modalId}`).addClass("modal--active")
        $("body").addClass("fixed-body")
    }

    $(".modal").click(function () {
        closeModal()
    })

    $("._close-modal").click(function () {
        closeModal()
    })

    $(".modal__dialog").click(function (e) {
        e.stopPropagation()
    })

    function closeModal() {
        $('.modal--active video').each(function () {
            this.pause();
            this.currentTime = 0;
        });

        $('.modal').removeClass("modal--active")
        $("body").removeClass("fixed-body")
    }

})

// Send
$('.send-icon').on('click', function (e) {
    e.stopPropagation();

    $(this).closest('.send').toggleClass('send--active');
});

$(document).on('click', function (e) {
    if (!$(e.target).closest('.send').length) {
        $('.send').removeClass('send--active');
    }
});

// Textarea
$('#autoTextarea').on('input', function () {
    $(this).css('height', '40px');
    $(this).css('height', this.scrollHeight + 'px');
});

