document.addEventListener('DOMContentLoaded', function () {

    function formatNumber(value) {
        if (value === '' || value === null) return '';
        return new Intl.NumberFormat('ru-RU').format(value);
    }

    function unformatNumber(value) {
        if (!value) return '';
        return value.toString().replace(/\s/g, '');
    }

    function initSlider(sliderElement) {
        const min = parseFloat(sliderElement.dataset.min) || 0;
        const max = parseFloat(sliderElement.dataset.max) || 100;
        const start = sliderElement.dataset.start.split(',').map(Number);
        const step = parseFloat(sliderElement.dataset.step) || 1;

        const config = {
            start: start,
            connect: true,
            range: {
                min: min,
                max: max
            },
            step: step,
            format: {
                to: function (value) {
                    return Math.round(value);
                },
                from: function (value) {
                    return Number(value);
                }
            }
        };

        noUiSlider.create(sliderElement, config);

        const rangeElement = sliderElement.closest('.range');
        const groupElement = sliderElement.closest('.step-group');

        const minInput = rangeElement.querySelector('[data-slider="min"]');
        const maxInput = rangeElement.querySelector('[data-slider="max"]');

        const radios = groupElement.querySelectorAll('input[type="radio"]');

        minInput.value = formatNumber(start[0]);
        maxInput.value = formatNumber(start[1]);

        sliderElement.noUiSlider.on('update', function (values, handle) {
            const minVal = Math.round(values[0]);
            const maxVal = Math.round(values[1]);

            if (handle === 0) {
                minInput.value = formatNumber(minVal);
            } else {
                maxInput.value = formatNumber(maxVal);
            }

            let matched = false;

            radios.forEach(radio => {
                const rMin = Number(radio.dataset.min);
                const rMax = Number(radio.dataset.max);

                if (minVal === rMin && maxVal === rMax) {
                    radio.checked = true;
                    matched = true;
                }
            });

            if (!matched) {
                radios.forEach(radio => radio.checked = false);
            }
        });

        minInput.addEventListener('change', function () {
            const value = unformatNumber(this.value);
            sliderElement.noUiSlider.set([value || null, null]);
        });

        maxInput.addEventListener('change', function () {
            const value = unformatNumber(this.value);
            sliderElement.noUiSlider.set([null, value || null]);
        });

        [minInput, maxInput].forEach(input => {

            input.addEventListener('focus', function () {
                this.value = unformatNumber(this.value);
            });

            input.addEventListener('blur', function () {
                let value = unformatNumber(this.value);
                if (value !== '') {
                    this.value = formatNumber(value);
                }
            });

            input.addEventListener('keydown', function (e) {
                if (e.key === 'Enter') {
                    e.preventDefault();
                    this.blur();
                }
            });

        });

        radios.forEach(radio => {
            radio.addEventListener('change', function () {
                if (!this.checked) return;

                const rMin = this.dataset.min;
                const rMax = this.dataset.max;

                if (rMin !== undefined && rMax !== undefined) {
                    sliderElement.noUiSlider.set([rMin, rMax]);
                }
            });
        });
    }

    document.querySelectorAll('.range__slider').forEach(initSlider);

});
